import { HttpError } from 'wasp/server'
import type { GetMyTeams, GetTeamTasks } from 'wasp/server/operations'

export const getMyTeams: GetMyTeams<void, any> = async (args, context) => {
  if (!context.user) {
    throw new HttpError(401)
  }

  return context.entities.Team.findMany({
    where: {
      members: {
        some: {
          id: context.user.id
        }
      }
    },
    include: {
      members: true
    }
  })
}

export const getTeamTasks: GetTeamTasks<{ teamId: number }, any> = async (args, context) => {
  if (!context.user) {
    throw new HttpError(401)
  }

  const team = await context.entities.Team.findFirst({
    where: {
      id: args.teamId,
      members: {
        some: {
          id: context.user.id
        }
      }
    },
    include: {
      tasks: true
    }
  })

  if (!team) {
    throw new HttpError(403, 'You are not a member of this team')
  }

  return team.tasks
}

