import { HttpError } from 'wasp/server'
import type { CreateTeam, CreateTask } from 'wasp/server/operations'

export const createTeam: CreateTeam<{ name: string }, any> = async (args, context) => {
  if (!context.user) {
    throw new HttpError(401)
  }

  return context.entities.Team.create({
    data: {
      name: args.name,
      members: {
        connect: { id: context.user.id }
      }
    }
  })
}

export const createTask: CreateTask<{ teamId: number; description: string }, any> = async (args, context) => {
  if (!context.user) {
    throw new HttpError(401)
  }

  const team = await context.entities.Team.findFirst({
    where: {
      id: args.teamId,
      members: {
        some: {
          id: context.user.id
        }
      }
    }
  })

  if (!team) {
    throw new HttpError(403, 'Only team members can create tasks for this team')
  }

  return context.entities.Task.create({
    data: {
      description: args.description,
      team: {
        connect: { id: args.teamId }
      }
    }
  })
}

