import { useParams, Link } from 'react-router-dom'
import { useQuery, useAction, getTeamTasks, createTask } from 'wasp/client/operations'
import { useState } from 'react'

export const TeamPage = () => {
  const { id } = useParams()
  const teamId = parseInt(id!)
  const { data: tasks, isLoading, error } = useQuery(getTeamTasks, { teamId })
  const createTaskAction = useAction(createTask)
  const [taskDescription, setTaskDescription] = useState('')

  const handleCreateTask = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!taskDescription) return
    try {
      await createTaskAction({ teamId, description: taskDescription })
      setTaskDescription('')
    } catch (err: any) {
      alert(err.message)
    }
  }

  if (isLoading) return <div>Loading...</div>
  if (error) return <div>Error: {error.message}</div>

  return (
    <div style={{ padding: '20px' }}>
      <Link to="/">Back to Dashboard</Link>
      <h1>Team Tasks</h1>
      <ul>
        {tasks?.map((task: any) => (
          <li key={task.id}>
            {task.description} {task.isDone ? '(Done)' : '(Pending)'}
          </li>
        ))}
      </ul>

      <h3>Add a New Task</h3>
      <form onSubmit={handleCreateTask}>
        <input
          type="text"
          placeholder="Task Description"
          value={taskDescription}
          onChange={(e) => setTaskDescription(e.target.value)}
        />
        <button type="submit">Add Task</button>
      </form>
    </div>
  )
}

